	@Test
	void printCycle5MetricsForExecutorAndFullCodegen() throws Exception {
		MetricsSnapshot executor = executeCycle5(LmdbLftjCodegenCompiler.INSTANCE);
		MetricsSnapshot full = executeCycle5(LmdbLftjFullCodegenCompiler.INSTANCE);

		System.out.println("executor cycle5 metrics: " + executor);
		System.out.println("full cycle5 metrics: " + full);

		assertThat(executor.emittedBindings).isPositive();
		assertThat(full.emittedBindings).isEqualTo(executor.emittedBindings);
		assertThat(full.frontierHits).isPositive();
		assertThat(full.countHits).isPositive();
		assertThat(full.relationUses).isLessThan(full.witnessScans);
	}

